import{_ as t}from"./plugin-vue_export-helper-c27b6911.js";import{r as a,o as n,c as r,a as e,b as o,d as i,e as c}from"./app-a96f739b.js";const s={},l=c('<h2 id="网络基础-tcp-ip" tabindex="-1"><a class="header-anchor" href="#网络基础-tcp-ip" aria-hidden="true">#</a> 网络基础 TCP/IP</h2><p>为了理解 HTTP，我们有必要事先了解一下 TCP/IP 协议族。</p><p>通常使用的网络(包括互联网)是在 TCP/IP 协议族的基础上运作 的。而 HTTP 属于它内部的一个子集。</p><h3 id="tcp-ip-协议族" tabindex="-1"><a class="header-anchor" href="#tcp-ip-协议族" aria-hidden="true">#</a> TCP/IP 协议族</h3><p>TCP/IP 协议族是互联网相关的各类协议族的总称</p><img src="https://img.bookandmusic.cn/blog/2022/01/3nxdxi.png" alt="3nxdxi" style="zoom:33%;"><p>像这样把与互联网相关联的协议集合起来总称为 TCP/IP。也有说法 认为，TCP/IP 是指 TCP 和 IP 这两种协议。还有一种说法认为，TCP/ IP 是在 IP 协议的通信过程中，使用到的协议族的统称。</p><h3 id="tcp-ip-分层管理" tabindex="-1"><a class="header-anchor" href="#tcp-ip-分层管理" aria-hidden="true">#</a> TCP/IP 分层管理</h3><p>TCP/IP 协议族里重要的一点就是分层。TCP/IP 协议族按层次分别分为以下 4 层:</p><p><strong>应用层</strong>：决定向用户提供应用服务时通信的活动，<br><code>FTP(File Transfer Protocol)</code> 文件传输协议、<code>DNS</code>(<code>Domain Name System</code>) 域名系统、<code>HTTP</code>(<code>HyperText Transfer Protocol</code>)<br><strong>传输层</strong>：提供处于网络连接中两台计算机之间的数据传输。<br><code>TCP</code>(<code>Transmission Control Protocol</code>) 传输控制协议、<code>UDP</code>(<code>User Data Protocol</code>) 用户数据报协议<br><strong>网络层（网络互联层）</strong>：处理在网络上流动的数据包（数据包是网络传输的最小数据单位）。该层规定了通过怎样的路径（传输路线）到达对方计算机，并传递数据。作用就是在与对方计算机之间通过多台计算机或网络设备进行传输时，选择一条传输路线。<br><strong>链路层（数据链路层、网络接口层）</strong>：用来处理网络的硬件部分。包括控制操作系统、硬件设备驱动、<code>NIC</code>（<code>Network Interface Card</code>，网络适配器）、光纤等物理课件部分（连接器等一切传输媒介）。</p><h3 id="tcp-ip-通信传输流" tabindex="-1"><a class="header-anchor" href="#tcp-ip-通信传输流" aria-hidden="true">#</a> TCP/IP 通信传输流</h3><img src="https://img.bookandmusic.cn/blog/2022/01/cFJOVh.png" alt="cFJOVh" style="zoom:50%;"><p>应用发请求通过 <code>TCP</code> 处理报文进行分隔发送给网络层网络层增加 <code>MAC</code> 地址给链路, 之后反向操作, 请求数据的时候每一层处理完成后会给这个数据加上这个层的首部信息, 相反, 处理请求的时候, 每处理一层就删除一个首部, 这叫做数据信息的封装 (<code>encapsulate</code>)。</p><img src="https://img.bookandmusic.cn/blog/2022/01/Nuc4MS.png" alt="Nuc4MS" style="zoom:50%;"><h2 id="与-http-关系密切的协议-ip、tcp-和dns" tabindex="-1"><a class="header-anchor" href="#与-http-关系密切的协议-ip、tcp-和dns" aria-hidden="true">#</a> 与 HTTP 关系密切的协议 : IP、TCP 和DNS</h2><h3 id="ip-协议" tabindex="-1"><a class="header-anchor" href="#ip-协议" aria-hidden="true">#</a> IP 协议</h3><p><code>IP</code>（<code>Internet Protocol</code>）网络协议处于网络层。几乎所有使用网络的系统都会用到 <code>IP</code> 协议。<code>IP</code> 不是 <code>IP</code> 地址，<code>IP</code> 只是一种协议名称。</p><ul><li><p>作用：把各种数据包传给对方，保证能传送到达需要多种条件，其中最重要的是 <code>IP</code> 地址和 <code>MAC</code>（<code>Media Access Control Address</code>) 地址。</p></li><li><p><code>IP</code> 地址：指明节点被分配到的地址</p></li><li><p><code>MAC</code> 地址： 网卡所属的固定地址</p></li><li><p><code>IP</code> 地址可以和 <code>MAC</code> 地址进行配对，<code>IP</code> 可变，但 <code>MAC</code> 基本不会更改。</p><p>不同局域网之间的通信需要经过多次中转，在中转时会利用下一站中转设备的 <code>MAC</code> 地址来搜索下一个中转目标，这时会采用 <code>ARP</code> 协议（<code>Addres s Resolution Protocol</code>)，这是用于解析地址的协议，可以根据对方 <code>IP</code> 地址就能反查处对应的 <code>MAC</code> 地址。<br>   信息传输的时候，并不是从一开始就设计好精确的路线，而是边走边瞧，到下一个中转点会自动判断下一个中转点，这叫做路由选择（<code>routing</code>）</p></li></ul><img src="https://img.bookandmusic.cn/blog/2022/01/h5okGJ.png" alt="h5okGJ" style="zoom:50%;"><h3 id="tcp-协议" tabindex="-1"><a class="header-anchor" href="#tcp-协议" aria-hidden="true">#</a> TCP 协议</h3><p>按层次位于传输层, 提供可靠的字节流服务 (<code>Byte Stream Service</code>), 意思是为了方便传输, 将大块数据分割成以报文段(<code>segment</code>) 为单位的数据包进行管理可靠的传输服务是指，能够把数据准确可靠的传给对方。</p><p>如何确保数据到达目标：三次握手（<code>three—way handshaking</code>）策略</p><figure><img src="https://img.bookandmusic.cn/blog/2022/01/z0wChT.png" alt="z0wChT" tabindex="0" loading="lazy"><figcaption>z0wChT</figcaption></figure><ul><li>发送端先发送一个带有 <code>SYN</code>（<code>synchronize</code> 同步）标识的数据包给对方</li><li>对方接收到后回传一个带有  <code>SYN</code>/<code>ACK</code>（<code>acknowledgement</code>)标识的数据包已传达确认信息</li><li>最后发送端再传回一个带有 <code>ACK</code> 标识的数据包代表 “握手” 结束。</li><li>若期间在某个过程莫名中断, <code>TCP</code> 协议会在此以相同顺序发送相同数据包。</li></ul><h3 id="dns-服务" tabindex="-1"><a class="header-anchor" href="#dns-服务" aria-hidden="true">#</a> DNS 服务</h3>',25),h=e("code",null,"DNS",-1),p=e("code",null,"HTTP",-1),P=e("code",null,"域名",-1),T=e("code",null,"IP",-1),g=e("br",null,null,-1),u=e("code",null,"IP",-1),m={href:"http://www.baidu.com",target:"_blank",rel:"noopener noreferrer"},b=e("code",null,"119.75.217.109",-1),f=e("code",null,"DNS",-1),_=c('<figure><img src="https://img.bookandmusic.cn/blog/2022/01/NqMfuZ.png" alt="NqMfuZ" tabindex="0" loading="lazy"><figcaption>NqMfuZ</figcaption></figure><h3 id="各种协议与-http-协议的关系" tabindex="-1"><a class="header-anchor" href="#各种协议与-http-协议的关系" aria-hidden="true">#</a> 各种协议与 HTTP 协议的关系</h3><p>客户端发出对某 <code>www.</code> 网站的请求, 通过 <code>DNS</code> 协议获取对应的 <code>IP</code> 地址, 在通过 <code>HTTP</code> 协议生成请求报文, 通过 <code>TCP</code> 进行分隔划分成数据包, 通过三次握手把每个报文段可靠的传给对方, 再通过 <code>IP</code> 协议分配 <code>IP</code> 地址和 <code>MAC</code> 地址, 一遍中转一遍传送, 对方通过 <code>IP</code> 协议接收一段段报文, 通过 <code>TCP</code> 协议再一段段重组, 在通过 <code>HTTP</code> 协议对这些内容进行处理请求信息, 把请求结果再像上边的过程走回客户端。一次完整的传输就结束了。</p><img src="https://img.bookandmusic.cn/blog/2022/01/zXAvKP.png" alt="zXAvKP" style="zoom:50%;"><h2 id="uri-和-url" tabindex="-1"><a class="header-anchor" href="#uri-和-url" aria-hidden="true">#</a> URI 和 URL</h2>',5),I=e("code",null,"URL",-1),C=e("code",null,"Uniform",-1),x=e("code",null,"Resource",-1),k=e("code",null,"Locator",-1),H=e("code",null,"Web",-1),w=e("code",null,"web",-1),N={href:"http://www.baidu.com",target:"_blank",rel:"noopener noreferrer"},y=c("<li><code>URI</code>（<code>Uniform</code> <code>Resource</code> <code>Identifier</code>) 统一资源标识符</li><li><em><code>Uniform</code></em> 规定统一格式可方便处理多种不同类型资源。</li><li><em><code>Resouce</code></em> 资源定义是 “可标识的任何东西”。</li><li><em><code>Identifier</code></em> 可标识的对象。也称作标识符。</li>",4),z=c('<p>综上，<code>URI</code> 就是由某协议方案表示的资源的定位标识符，其中，访问资源所使用的协议类型， <code>HTTP</code> 协议时，协议方案就是 <code>http</code>，除此还有 <code>ftp</code>、<code>mailto</code>、<code>telent</code>、<code>file</code> 等。<br>   <code>URI</code> 用字符串标识某一互联网资源，<code>URL</code> 表示资源的地点，可见 <code>URL</code> 是 <code>URI</code> 的子集。</p><p>绝对 <code>URI</code> 格式：</p><figure><img src="https://img.bookandmusic.cn/blog/2022/01/f7JIbe.png" alt="f7JIbe" tabindex="0" loading="lazy"><figcaption>f7JIbe</figcaption></figure><p>可选项：登录信息、服务器端口号、查询字符串、片段标识符</p><h2 id="http介绍" tabindex="-1"><a class="header-anchor" href="#http介绍" aria-hidden="true">#</a> HTTP介绍</h2><p>HTTP 协议一般指 HTTP（超文本传输协议）。</p><p>超文本传输协议（英语：HyperText Transfer Protocol，缩写：HTTP）是一种用于分布式、协作式和超媒体信息系统的应用层协议，是因特网上应用最为广泛的一种网络传输协议，所有的 WWW 文件都必须遵守这个标准。</p><p>HTTP是一个基于TCP/IP通信协议来传递数据（HTML 文件, 图片文件, 查询结果等）。</p><h2 id="http-工作原理" tabindex="-1"><a class="header-anchor" href="#http-工作原理" aria-hidden="true">#</a> HTTP 工作原理</h2><p>HTTP协议工作于客户端-服务端架构上。浏览器作为HTTP客户端通过URL向HTTP服务端即WEB服务器发送所有请求。</p><p>Web服务器有：Apache服务器，Nginx服务器，IIS服务器（Internet Information Services）等。</p><p>Web服务器根据接收到的请求后，向客户端发送响应信息。</p><p>HTTP默认端口号为80，但是你也可以改为8080或者其他端口。</p><p>**HTTP三点注意事项: **</p><ul><li>HTTP是无连接：无连接的含义是限制每次连接只处理一个请求。服务器处理完客户的请求，并收到客户的应答后，即断开连接。采用这种方式可以节省传输时间。</li><li>HTTP是媒体独立的：这意味着，只要客户端和服务器知道如何处理的数据内容，任何类型的数据都可以通过HTTP发送。客户端以及服务器指定使用适合的MIME-type内容类型。</li><li>HTTP是无状态：HTTP协议是无状态协议。无状态是指协议对于事务处理没有记忆能力。缺少状态意味着如果后续处理需要前面的信息，则它必须重传，这样可能导致每次连接传送的数据量增大。另一方面，在服务器不需要先前信息时它的应答就较快。</li></ul><h2 id="持久连接节省通信量" tabindex="-1"><a class="header-anchor" href="#持久连接节省通信量" aria-hidden="true">#</a> 持久连接节省通信量</h2><h3 id="持久化连接" tabindex="-1"><a class="header-anchor" href="#持久化连接" aria-hidden="true">#</a> 持久化连接</h3><p>当请求的资源有很多时，会发生多次的 <code>TCP</code> 连接和断开过程，增加了通信量的开销。于是产生了持久链接（<code>HTTP</code> <code>Persistent</code> <code>connections</code>）。<br>   <strong>特点：</strong> 只要任意一端没有明确提出断开连接，则保持 <code>TCP</code> 连接状态。</p><figure><img src="https://img.bookandmusic.cn/blog/2022/01/q9PJxt.png" alt="q9PJxt" tabindex="0" loading="lazy"><figcaption>q9PJxt</figcaption></figure><h3 id="管线化" tabindex="-1"><a class="header-anchor" href="#管线化" aria-hidden="true">#</a> 管线化</h3><p>持久化连接需要等待上一个发送请求得到响应之后才能发送下一个请求，但是管线化技术可以直接发送，这样就能同时并发发送多个请求。</p><figure><img src="https://img.bookandmusic.cn/blog/2022/01/58mBbD.png" alt="58mBbD" tabindex="0" loading="lazy"><figcaption>58mBbD</figcaption></figure><h2 id="使用-cookie-的状态管理" tabindex="-1"><a class="header-anchor" href="#使用-cookie-的状态管理" aria-hidden="true">#</a> 使用 <strong>Cookie</strong> 的状态管理</h2><p>状态管理。为了解决 <code>HTTP</code> 的无状态，<code>Cookie</code> 技术通过在请求和响应报文中写入 <code>Cookie</code> 信息来控制客户端的状态。具体实现是 <code>Cookie</code> 根据响应报文内 <code>Set-Cookie</code> 的首部字段信息，通知客户端保存 <code>Cookie</code>，当下一次再像<strong>该</strong>服务器发送请求，客户端会自动在请求报文中添加 <code>Cookie</code> 值后发送。服务端发现客户端发送的 <code>Cookie</code> 后，回去检查对比记录，得到状态信息。</p><img src="https://img.bookandmusic.cn/blog/2022/01/Jnc7Kv.png" alt="Jnc7Kv" style="zoom:50%;">',25);function A(M,S){const d=a("ExternalLinkIcon");return n(),r("div",null,[l,e("p",null,[h,o(" 服务是和 "),p,o(" 一样位于应用层, 提供"),P,o("到 "),T,o(" 地址之间的解析服务。"),g,o("  计算机可以有 "),u,o(" 地址, 又可以有主机名和域名。比如可以使用 "),e("a",m,[o("www.baidu.com"),i(d)]),o(" 访问百度，也可以使用 "),b,o(" 访问百度。"),f,o(" 协议就是可以查询其对应关系的协议。")]),_,e("ul",null,[e("li",null,[I,o("（"),C,o(),x,o(),k,o(") 统一资源定位符，就是 "),H,o(" 浏览器访问 "),w,o(" 页面时候的网页地址，"),e("a",N,[o("http://www.baidu.com"),i(d)])]),y]),z])}const D=t(s,[["render",A],["__file","HTTP简介-495fc282.html.vue"]]);export{D as default};
